            {"he": "נסיבות", "ru": "обстоятельства", "translit": "несибОт"},
            {"he": "אוסף", "ru": "собрание, коллекция", "translit": "Осеф"},
            {"he": "כתב יד", "ru": "почерк", "translit": "ктав яд"},
